+++ b/clients/src/main/java/org/apache/kafka/common/config/ConfigDef.java
@@ -577,10 +577,44 @@ public class ConfigDef {
             configValues.put(undefinedConfigKey, undefinedConfigValue);
         }

+        checkForDependentCycles();
+
         Map<String, Object> parsed = parseForValidate(props, configValues);
         return validate(parsed, configValues);
     }

+    private void checkForDependentCycles() {
+        Set<String> visited = new HashSet<>();
+        Set<String> inProgress = new HashSet<>();
+        for (String name : configKeys.keySet()) {
+            if (!visited.contains(name)) {
+                detectCycle(name, visited, inProgress, new ArrayList<>());
+            }
+        }
+    }
+
+    private void detectCycle(String name, Set<String> visited, Set<String> inProgress, List<String> path) {
+        if (inProgress.contains(name)) {
+            List<String> cyclePath = new ArrayList<>(path);
+            cyclePath.add(name);
+            throw new ConfigException("Circular dependency detected in config dependents: " + String.join(" -> ", cyclePath));
+        }
+        if (visited.contains(name)) {
+            return;
+        }
+        inProgress.add(name);
+        path.add(name);
+        ConfigKey key = configKeys.get(name);
+        if (key != null) {
+            for (String dependent : key.dependents) {
+                detectCycle(dependent, visited, inProgress, path);
+            }
+        }
+        path.remove(path.size() - 1);
+        inProgress.remove(name);
+        visited.add(name);
+    }
+
